import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import { useToast } from '../../context/ToastContext';
import './DocumentList.css';

const DocumentList = ({ patientId }) => {
    const [documents, setDocuments] = useState([]);
    const [loading, setLoading] = useState(true);
    const { showError } = useToast();

    useEffect(() => {
        fetchDocuments();
    }, [patientId]);

    const fetchDocuments = async () => {
        try {
            const response = await api.get(`/health-records`);
            setDocuments(response.data || []);
        } catch (error) {
            console.error('Error fetching documents:', error);
            showError('Failed to load documents');
        } finally {
            setLoading(false);
        }
    };

    const handleDownload = async (attachmentId, fileName) => {
        try {
            const response = await api.get(`/health-records/attachments/${attachmentId}/download`, {
                responseType: 'blob'
            });
            
            const url = window.URL.createObjectURL(new Blob([response.data]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', fileName);
            document.body.appendChild(link);
            link.click();
            link.remove();
            window.URL.revokeObjectURL(url);
        } catch (error) {
            console.error('Download error:', error);
            showError('Failed to download document');
        }
    };

    const getFileIcon = (fileType) => {
        if (fileType.includes('pdf')) return '📄';
        if (fileType.includes('image')) return '🖼️';
        if (fileType.includes('word')) return '📝';
        return '📎';
    };

    if (loading) return <div className="loading-docs">Loading documents...</div>;

    return (
        <div className="document-list">
            <h3>Patient Documents</h3>
            {documents.length === 0 ? (
                <div className="no-documents">
                    <p>No documents uploaded yet</p>
                </div>
            ) : (
                <div className="documents-grid">
                    {documents.map(record => {
                        // Parse record data to get attachments
                        const attachments = record.attachments || [];
                        return attachments.map(attachment => (
                            <div key={attachment.id} className="document-card">
                                <div className="document-icon">
                                    {getFileIcon(attachment.file_type)}
                                </div>
                                <div className="document-info">
                                    <div className="document-name">{attachment.file_name}</div>
                                    <div className="document-meta">
                                        <span className="document-date">
                                            {new Date(attachment.uploaded_at).toLocaleDateString()}
                                        </span>
                                        <span className="document-size">
                                            {(attachment.file_size / (1024 * 1024)).toFixed(2)} MB
                                        </span>
                                    </div>
                                    {attachment.description && (
                                        <div className="document-description">{attachment.description}</div>
                                    )}
                                </div>
                                <button 
                                    onClick={() => handleDownload(attachment.id, attachment.file_name)}
                                    className="download-button"
                                >
                                    📥 Download
                                </button>
                            </div>
                        ));
                    })}
                </div>
            )}
        </div>
    );
};

export default DocumentList;
